# Parse /usr/stock.log: last two columns are stock index and count.
# Determine which stock indices Bob sold but never bought.
# Assumption: log lines contain 'Bob' and an action keyword 'sold' or 'bought'.
# We'll extract stock index from last-but-one column and count from last column.
log=/usr/stock.log
if [ ! -f "$log" ]; then
  echo "missing"; exit 1
fi
# Extract Bob sold/bought stock indices
sold=$(awk 'BEGIN{IGNORECASE=1}
  $0 ~ /Bob/ && $0 ~ /sold/ {
    idx=$(NF-1); c=$NF;
    if (c+0!=0) print idx
  }' "$log" | sort -u)
