  $0 ~ /Bob/ && $0 ~ /bought/ {
    idx=$(NF-1); c=$NF;
    if (c+0!=0) print idx
  }' "$log" | sort -u)
# Count indices in sold not in bought
count=$(comm -23 <(printf "%s\n" "$sold") <(printf "%s\n" "$bought") | sed '/^$/d' | wc -l)
echo "$count""}

